class JobPayload:
    """Structured job payload - replaces arbitrary object deserialization."""

    def __init__(self, job_id: str, job_type: str, parameters: Dict[str, Any],
                 created_at: str, signature: Optional[str] = None):
        self.job_id = job_id
        self.job_type = job_type
        self.parameters = parameters
        self.created_at = created_at
        self.signature = signature

    @classmethod
    def from_dict(cls, data: Dict[str, Any]) -> "JobPayload":
        """Create JobPayload from a validated dictionary."""
        required_fields = {"job_id", "job_type", "parameters", "created_at"}
        missing = required_fields - set(data.keys())
        if missing:
            raise ValueError(f"Missing required fields: {missing}")

        if data["job_type"] not in ALLOWED_JOB_TYPES:
            raise ValueError(f"Invalid job_type: {data['job_type']}. "
                             f"Allowed: {ALLOWED_JOB_TYPES}")

        if not isinstance(data["parameters"], dict):
            raise ValueError("Parameters must be a dictionary")

        # Validate job_id format (alphanumeric + hyphens only)
        job_id = data["job_id"]
        if not isinstance(job_id, str) or not all(
            c.isalnum() or c == '-' for c in job_id
        ):
            raise ValueError(f"Invalid job_id format: {job_id}")

        return cls(
            job_id=job_id,
            job_type=data["job_type"],
            parameters=data["parameters"],
            created_at=data["created_at"],
            signature=data.get("signature"),
        )

    def to_dict(self) -> Dict[str, Any]:
        return {
            "job_id": self.job_id,
            "job_type": self.job_type,
            "parameters": self.parameters,
            "created_at": self.created_at,
        }


def verify_message_signature(payload: JobPayload) -> bool:
    """Verify HMAC signature of the message to ensure authenticity."""
    signing_key = os.environ.get("MESSAGE_SIGNING_KEY")
    if not signing_key:
        logging.warning("MESSAGE_SIGNING_KEY not configured - skipping verification")
        return False

    if not payload.signature:
        logging.warning(f"Job {payload.job_id}: No signature present")
        return False

    message_bytes = json.dumps(payload.to_dict(), sort_keys=True).encode("utf-8")
    expected_sig = hmac.new(
        signing_key.encode("utf-8"), message_bytes, hashlib.sha256
    ).hexdigest()

    return hmac.compare_digest(expected_sig, payload.signature)


