def main(msg: func.ServiceBusMessage) -> None:
    """
    Azure Function triggered by Service Bus queue messages.
    
    Uses JSON deserialization (NOT pickle) for security.
    Messages should be JSON-encoded JobPayload structures.
    """
    message_id = msg.message_id
    logging.info(f"Processing Service Bus message: {message_id}")

    try:
        # SECURE: Deserialize using JSON (safe, no code execution)
        message_body = msg.get_body().decode("utf-8")
        raw_data = json.loads(message_body)

        # Validate and parse into structured payload
        payload = JobPayload.from_dict(raw_data)
        logging.info(f"Job {payload.job_id}: type={payload.job_type}, "
                     f"created_at={payload.created_at}")

        # Verify message signature (defense in depth)
        if os.environ.get("REQUIRE_SIGNED_MESSAGES", "false").lower() == "true":
            if not verify_message_signature(payload):
                logging.error(f"Job {payload.job_id}: Invalid or missing signature. "
                              f"Rejecting message.")
                raise ValueError("Message signature verification failed")
            logging.info(f"Job {payload.job_id}: Signature verified")

        # Dispatch to appropriate handler
        handler = JOB_HANDLERS.get(payload.job_type)
        if handler is None:
            raise ValueError(f"No handler registered for job_type: {payload.job_type}")

        result = handler(payload.parameters)
        logging.info(f"Job {payload.job_id}: Completed with result: {result}")

    except json.JSONDecodeError as e:
        logging.error(f"Message {message_id}: Invalid JSON - {e}")
        raise  # Let Service Bus handle dead-lettering

    except ValueError as e:
        logging.error(f"Message {message_id}: Validation error - {e}")
        raise  # Let Service Bus handle dead-lettering

    except Exception as e:
        logging.error(f"Message {message_id}: Processing failed - {e}")
        raise  # Let Service Bus handle retry/dead-lettering


