def create_signed_message(job_id: str, job_type: str,
                          parameters: Dict[str, Any],
                          signing_key: str) -> str:
    """
    Creates a signed JSON message for sending to the queue.
    Use this in your message producers instead of pickle.dumps().
    """
    payload = {
        "job_id": job_id,
        "job_type": job_type,
        "parameters": parameters,
        "created_at": datetime.utcnow().isoformat(),
    }

    signature = hmac.new(
        signing_key.encode("utf-8"),
        json.dumps(payload, sort_keys=True).encode("utf-8"),
        hashlib.sha256,
    ).hexdigest()

    payload["signature"] = signature
    return json.dumps(payload)